final:
module RefModule (
    input clk,
    input rst,
    input [3:0] bin,
    output [3:0] gray
);

reg [3:0] gray_reg;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (rst) begin
        gray_reg <= 4'b0;
    end else begin
        gray_reg <= bin ^ (bin >> 1);
    end
end

assign gray = gray_reg;

endmodule
